(null, 'billiards-table-plus', 'Billiards Table Plus Game-Room Items', 'general-merchandise', 'unmanifested', 'customer-return', 310, 310, 1, 310, 'in-stock', array['/images/savemore/billiards-table-plus-1.webp'], 'A pool table with related game-room items and accessories, sold as-is from overstock or returns. A high-ticket local-sale fixture for game rooms, bars, and rec spaces, inspect rails, felt, and cues before resale.', 270),
(null, 'gaylord-liquidation-pallet', 'Gaylord Pallet, Bulk Mixed Merchandise', 'general-merchandise', 'unmanifested', 'customer-return', 340, 340, 1, 340, 'in-stock', array['/images/savemore/gaylord-liquidation-pallet-1.webp'], 'A gaylord-size container of bulk assorted merchandise, packing high piece counts of small-to-medium items across home, accessories, and general goods. Unmanifested overstock and returns for resellers who profit on volume and variety.', 271),
(null, 'bj-s-smalls-hpc', 'BJ''s Smalls High-Piece-Count Pallet', 'general-merchandise', 'unmanifested', 'customer-return', 385, 385, 1, 385, 'in-stock', array['/images/savemore/bj-s-smalls-hpc-1.webp'], 'A high-piece-count pallet of small-format items from BJ''s Wholesale Club, mixing general merchandise, health, beauty, and household smalls. Inspected overstock and returns built to maximize unit count for bin stores pricing by the each.', 272),
(null, 'mini-dhl-heavy-in-clothes', 'DHL Returned-Parcel Pallet, Heavy in Clothes', 'apparel', 'unmanifested', 'customer-return', 220, 220, 1, 220, 'in-stock', array['/images/savemore/mini-dhl-heavy-in-clothes-1.webp'], 'A mixed parcel-return pallet running heavy in apparel, built from undelivered and returned shipments plus overstock. Mixed men''s, women''s, and kids clothing across tops, bottoms, loungewear, and outerwear, a low cost-basis entry into ready-to-flip garments.', 273),
(null, 'large-liquidation-pallet', 'Large Liquidation Pallet, Higher-Retail Mix', 'general-merchandise', 'unmanifested', 'customer-return', 700, 700, 1, 700, 'in-stock', array['/images/savemore/large-liquidation-pallet-1.webp'], 'A high-value pallet of mixed general merchandise weighted toward bigger-ticket, higher-retail items across many categories. Unmanifested overstock and returns for resellers chasing stronger per-piece recovery and the higher-value finds.', 274),
(null, 'bj-s-seasonal-christmas-easter', 'BJ''s Christmas & Easter Seasonal Pallet', 'general-merchandise', 'unmanifested', 'customer-return', 440, 440, 1, 440, 'in-stock', array['/images/savemore/bj-s-seasonal-christmas-easter-1.webp'], 'A BJ''s Wholesale Club pallet of dual-holiday seasonal merchandise: Christmas decor, gifts, Easter and spring goods, and party items. One buy gives resellers two demand windows to sell into at $440.', 275),
(null, 'double-stacked-random', 'Double-Stacked Mixed Merchandise Pallet', 'general-merchandise', 'unmanifested', 'customer-return', 270, 270, 1, 270, 'in-stock', array['/images/savemore/double-stacked-random-1.webp'], 'Roughly two pallets of mixed general merchandise stacked into one load: home, kitchen, accessories, toys, seasonal, and small electronics. Unmanifested and built for resellers who want maximum piece count and variety at $270.', 276),
(null, 'craft-sewing', 'Craft & Sewing Supplies Pallet', 'general-merchandise', 'unmanifested', 'customer-return', 270, 270, 1, 270, 'in-stock', array['/images/savemore/craft-sewing-1.webp'], 'A focused pallet of craft and sewing inventory: thread, needles, bobbins, trims, fabric, yarn, and maker tools. Inspected and ready for quilters, sewists, and craft-fair vendors at $270 by the pallet.', 277),
(null, 'temu-pallet', 'Temu Overstock & Returns Pallet', 'general-merchandise', 'unmanifested', 'customer-return', 810, 810, 1, 810, 'in-stock', array['/images/savemore/temu-pallet-1.webp'], 'A high-piece-count pallet of mixed Temu-style overstock and returns: small gadgets, electronic accessories, home and kitchen items, jewelry, tools, and novelty goods. Priced at $810 for resellers who move volume through bin stores.', 278),
(null, 'mail-stacked-pallet', 'Stacked Undelivered Mail Parcel Pallet', 'general-merchandise', 'unmanifested', 'customer-return', 800, 800, 1, 800, 'in-stock', array['/images/savemore/mail-stacked-pallet-1.webp'], 'Undelivered and returned parcels stacked into one high-count load, each box a separate order in original packaging. Cross-category mix of electronics, home, beauty, toys, and accessories at $800 for unboxing-driven resale.', 279),
(null, 'bj-s-wholesale-soft-goods', 'BJ''s Soft Goods Pallet', 'general-merchandise', 'unmanifested', 'customer-return', 220, 220, 1, 220, 'in-stock', array['/images/savemore/bj-s-wholesale-soft-goods-1.webp'], 'A BJ''s Wholesale Club pallet of textiles, apparel, and home soft goods: clothing, bedding, towels, and fabric items in club and multipack formats. Easy to handle and sell broadly at $220 by the pallet.', 280),
(null, 'plastic-fuel-tanks', 'Plastic Fuel Tanks Wholesale Lot', 'general-merchandise', 'unmanifested', 'customer-return', 310, 310, 1, 310, 'in-stock', array['/images/savemore/plastic-fuel-tanks-1.webp'], 'A parts-driven lot of replacement plastic fuel tanks in mixed sizes and fitments for automotive, marine, powersports, and small-equipment use. Inspected overstock and shelf-pull stock at $310 for parts resellers who match by fitment.', 281),
(null, 'bj-s-clothing-christmas', 'BJ''s Christmas Apparel Pallet', 'apparel', 'unmanifested', 'customer-return', 728, 728, 1, 728, 'in-stock', array['/images/savemore/bj-s-clothing-christmas-1.webp'], 'A BJ''s Wholesale Club lot of Christmas-themed apparel: festive sweaters, pajamas, family sets, and holiday clothing for men, women, and kids. A larger seasonal buy at $728 built for the November-into-December window.', 282),
(null, 'dragons-3d-printed', 'Articulated 3D Printed Dragons Lot', 'general-merchandise', 'unmanifested', 'customer-return', 445, 445, 1, 445, 'in-stock', array['/images/savemore/dragons-3d-printed-1.webp'], 'A novelty lot of articulated, flexible 3D printed dragons in mixed colors and sizes. Lightweight impulse fidget toys that photograph well for short-form video, priced at $445 for live sellers and gift-shop resellers.', 283),
(null, 'hair-tools-pallet', 'Hair Tools Pallet', 'health-beauty', 'unmanifested', 'customer-return', 270, 270, 1, 270, 'in-stock', array['/images/savemore/hair-tools-pallet-1.webp'], 'A focused beauty pallet of powered styling tools: blow dryers, flat irons, curling wands, clippers, trimmers, and accessories across assorted brands. Inspected new, shelf-pull, and return stock at $270 by the pallet.', 284),
(null, 'kitchen-sink-pallet-11-units-total', 'Kitchen Sink Pallet (11 Units)', 'houseware', 'unmanifested', 'customer-return', 380, 380, 11, 34.55, 'in-stock', array['/images/savemore/kitchen-sink-pallet-11-units-total-1.webp'], 'Eleven kitchen sinks in one home-improvement lot: single-bowl, double-bowl, and assorted mount types across stainless, composite, and other materials. A known count at $380, roughly $35 per fixture for remodelers and contractors.', 285),
(null, 'christmas-tree-pallet-small-white-trees', 'Small White Christmas Trees Pallet', 'houseware', 'unmanifested', 'customer-return', 300, 300, 1, 300, 'in-stock', array['/images/savemore/christmas-tree-pallet-small-white-trees-1.webp'], 'A seasonal pallet of small white artificial Christmas trees in assorted compact sizes, boxed and display-ready. Tabletop and accent styles for apartments and offices, priced at $300 to stock ahead of the holiday window.', 286),
(null, 'hardware-pallet-hundreds-of-items', 'Hardware Pallet, Hundreds of Items', 'general-merchandise', 'unmanifested', 'customer-return', 270, 270, 1, 270, 'in-stock', array['/images/savemore/hardware-pallet-hundreds-of-items-1.webp'], 'A high-count hardware lot of hundreds of small home-improvement items: fasteners, fittings, brackets, fixtures, hand tools, and accessories. Mostly new and shelf-pull stock at $270, easy to price by the piece or by the bin.', 287),
(null, 'mixed-electronics-pallet', 'Mixed Consumer Electronics Pallet', 'electronics', 'unmanifested', 'customer-return', 520, 520, 1, 520, 'in-stock', array['/images/savemore/mixed-electronics-pallet-1.webp'], 'A high-retail pallet of assorted consumer electronics, gadgets, and accessories: possible audio, smart-home, lighting, and small devices. Sold as-is and worth testing on arrival, where a few working units can carry the $520 pallet.', 288)
